<template>
  <div class="user-list-container">
    <el-card>
      <!-- 搜索和过滤区域 -->
      <div class="filter-container">
        <el-form :inline="true" :model="listQuery" class="demo-form-inline">
          <el-form-item label="用户名称">
            <el-input v-model="listQuery.username" placeholder="用户名称" clearable></el-input>
          </el-form-item>
          <el-form-item label="手机号码">
            <el-input v-model="listQuery.phone" placeholder="手机号码" clearable></el-input>
          </el-form-item>
          <el-form-item label="注册时间">
            <el-date-picker
              v-model="dateRange"
              type="daterange"
              range-separator="至"
              start-placeholder="开始日期"
              end-placeholder="结束日期"
              value-format="yyyy-MM-dd"
              @change="handleDateChange"
            ></el-date-picker>
          </el-form-item>
          <el-form-item>
            <el-button type="primary" @click="handleSearch">查询</el-button>
            <el-button @click="resetQuery">重置</el-button>
          </el-form-item>
        </el-form>
      </div>
      
      <!-- 列表区域 -->
      <el-table
        v-loading="listLoading"
        :data="list"
        element-loading-text="加载中..."
        border
        fit
        highlight-current-row
      >
        <el-table-column prop="id" label="ID" width="80" align="center"></el-table-column>
        <el-table-column prop="username" label="用户名称" min-width="150">
          <template slot-scope="scope">
            <div class="user-info">
              <el-avatar :size="40" :src="scope.row.avatar">{{ getInitials(scope.row.username) }}</el-avatar>
              <div class="user-detail">
                <div class="username">{{ scope.row.username }}</div>
                <div class="nickname" v-if="scope.row.nickname">{{ scope.row.nickname }}</div>
              </div>
            </div>
          </template>
        </el-table-column>
        <el-table-column prop="phone" label="手机号码" width="120"></el-table-column>
        <el-table-column prop="gender" label="性别" width="80">
          <template slot-scope="scope">
            <span v-if="scope.row.gender === 'MALE'">男</span>
            <span v-else-if="scope.row.gender === 'FEMALE'">女</span>
            <span v-else>未知</span>
          </template>
        </el-table-column>
        <el-table-column prop="registerTime" label="注册时间" width="160"></el-table-column>
        <el-table-column prop="loginTime" label="最后登录" width="160"></el-table-column>
        <el-table-column prop="orderCount" label="订单数" width="80" align="center"></el-table-column>
        <el-table-column prop="spendAmount" label="消费金额" width="100">
          <template slot-scope="scope">
            <span v-if="scope.row.spendAmount">¥{{ scope.row.spendAmount.toFixed(2) }}</span>
            <span v-else>¥0.00</span>
          </template>
        </el-table-column>
        <el-table-column prop="status" label="状态" width="100">
          <template slot-scope="scope">
            <el-switch
              v-model="scope.row.status"
              :active-value="true"
              :inactive-value="false"
              @change="handleStatusChange(scope.row)"
              active-color="#13ce66"
              inactive-color="#ff4949">
            </el-switch>
          </template>
        </el-table-column>
        <el-table-column label="操作" width="150" fixed="right">
          <template slot-scope="scope">
            <el-button size="mini" @click="handleViewDetail(scope.row)">详情</el-button>
            <el-button 
              size="mini" 
              type="danger" 
              @click="handleResetPassword(scope.row)"
            >
              重置密码
            </el-button>
          </template>
        </el-table-column>
      </el-table>
      <el-empty v-if="!listLoading && list.length === 0" description="暂无数据" />
      
      <!-- 分页区域 -->
      <div class="pagination-container">
        <el-pagination
          background
          @size-change="handleSizeChange"
          @current-change="handleCurrentChange"
          :current-page="listQuery.page"
          :page-sizes="[10, 20, 30, 50]"
          :page-size="listQuery.pageSize"
          layout="total, sizes, prev, pager, next, jumper"
          :total="total"
        >
        </el-pagination>
      </div>
    </el-card>
    
    <!-- 用户详情对话框 -->
    <el-dialog title="用户详情" :visible.sync="detailDialogVisible" width="700px">
      <div v-loading="detailLoading" class="user-detail-container">
        <!-- 用户基本信息 -->
        <div class="detail-section">
          <h3 class="section-title">基本信息</h3>
          <div class="user-profile">
            <div class="user-avatar">
              <el-avatar :size="80" :src="currentUser.avatar">{{ getInitials(currentUser.username) }}</el-avatar>
            </div>
            <div class="user-basic-info">
              <el-row :gutter="20">
                <el-col :span="12">
                  <div class="info-item">
                    <span class="label">用户ID:</span>
                    <span class="value">{{ currentUser.id }}</span>
                  </div>
                </el-col>
                <el-col :span="12">
                  <div class="info-item">
                    <span class="label">用户名:</span>
                    <span class="value">{{ currentUser.username }}</span>
                  </div>
                </el-col>
              </el-row>
              <el-row :gutter="20">
                <el-col :span="12">
                  <div class="info-item">
                    <span class="label">昵称:</span>
                    <span class="value">{{ currentUser.nickname || '未设置' }}</span>
                  </div>
                </el-col>
                <el-col :span="12">
                  <div class="info-item">
                    <span class="label">性别:</span>
                    <span class="value">
                      <span v-if="currentUser.gender === 'MALE'">男</span>
                      <span v-else-if="currentUser.gender === 'FEMALE'">女</span>
                      <span v-else>未知</span>
                    </span>
                  </div>
                </el-col>
              </el-row>
              <el-row :gutter="20">
                <el-col :span="12">
                  <div class="info-item">
                    <span class="label">手机号码:</span>
                    <span class="value">{{ currentUser.phone || '未绑定' }}</span>
                  </div>
                </el-col>
                <el-col :span="12">
                  <div class="info-item">
                    <span class="label">微信OpenID:</span>
                    <span class="value">{{ currentUser.openId || '未绑定' }}</span>
                  </div>
                </el-col>
              </el-row>
              <el-row :gutter="20">
                <el-col :span="12">
                  <div class="info-item">
                    <span class="label">注册时间:</span>
                    <span class="value">{{ currentUser.registerTime }}</span>
                  </div>
                </el-col>
                <el-col :span="12">
                  <div class="info-item">
                    <span class="label">最后登录:</span>
                    <span class="value">{{ currentUser.loginTime }}</span>
                  </div>
                </el-col>
              </el-row>
            </div>
          </div>
        </div>
        
        <!-- 消费统计 -->
        <div class="detail-section">
          <h3 class="section-title">消费统计</h3>
          <div class="stat-cards">
            <el-row :gutter="20">
              <el-col :span="8">
                <div class="stat-card">
                  <div class="stat-value">{{ currentUser.orderCount || 0 }}</div>
                  <div class="stat-title">订单总数</div>
                </div>
              </el-col>
              <el-col :span="8">
                <div class="stat-card">
                  <div class="stat-value">¥{{ currentUser.spendAmount ? currentUser.spendAmount.toFixed(2) : '0.00' }}</div>
                  <div class="stat-title">消费总额</div>
                </div>
              </el-col>
              <el-col :span="8">
                <div class="stat-card">
                  <div class="stat-value">{{ currentUser.lastOrderTime || '无消费记录' }}</div>
                  <div class="stat-title">最近消费</div>
                </div>
              </el-col>
            </el-row>
          </div>
        </div>
        
        <!-- 收货地址 -->
        <div class="detail-section">
          <h3 class="section-title">收货地址</h3>
          <div v-if="currentUser.addresses && currentUser.addresses.length > 0">
            <div 
              v-for="(address, index) in currentUser.addresses" 
              :key="index"
              class="address-item"
              :class="{'default-address': address.isDefault}"
            >
              <div class="address-info">
                <div class="address-name">
                  {{ address.name }}
                  <span class="address-phone">{{ address.phone }}</span>
                  <el-tag v-if="address.isDefault" size="mini" type="success">默认</el-tag>
                </div>
                <div class="address-detail">{{ address.province }}{{ address.city }}{{ address.district }}{{ address.detail }}</div>
              </div>
            </div>
          </div>
          <div v-else class="empty-data">
            <i class="el-icon-location-information"></i>
            <p>暂无收货地址</p>
          </div>
        </div>
        
        <!-- 最近订单 -->
        <div class="detail-section">
          <h3 class="section-title">最近订单</h3>
          <div v-if="currentUser.recentOrders && currentUser.recentOrders.length > 0">
            <el-table :data="currentUser.recentOrders" border style="width: 100%">
              <el-table-column prop="orderNumber" label="订单号" width="180"></el-table-column>
              <el-table-column prop="createTime" label="下单时间" width="160"></el-table-column>
              <el-table-column prop="totalAmount" label="金额" width="100">
                <template slot-scope="scope">
                  <span class="amount">¥{{ scope.row.totalAmount.toFixed(2) }}</span>
                </template>
              </el-table-column>
              <el-table-column prop="status" label="状态" width="100">
                <template slot-scope="scope">
                  <el-tag :type="getOrderStatusType(scope.row.status)" size="mini">{{ orderStatusOptions[scope.row.status] }}</el-tag>
                </template>
              </el-table-column>
            </el-table>
          </div>
          <div v-else class="empty-data">
            <i class="el-icon-shopping-cart-2"></i>
            <p>暂无订单记录</p>
          </div>
        </div>
      </div>
    </el-dialog>
    
    <!-- 重置密码对话框 -->
    <el-dialog title="重置密码" :visible.sync="resetPwdDialogVisible" width="400px">
      <el-form :model="resetPwdForm" :rules="resetPwdRules" ref="resetPwdForm" label-width="100px">
        <el-form-item label="新密码" prop="password">
          <el-input v-model="resetPwdForm.password" type="password" placeholder="请输入新密码" show-password></el-input>
        </el-form-item>
        <el-form-item label="确认密码" prop="confirmPassword">
          <el-input v-model="resetPwdForm.confirmPassword" type="password" placeholder="请确认新密码" show-password></el-input>
        </el-form-item>
      </el-form>
      <div slot="footer" class="dialog-footer">
        <el-button @click="resetPwdDialogVisible = false">取 消</el-button>
        <el-button type="primary" @click="confirmResetPassword" :loading="resetPwdSubmitting">确 定</el-button>
      </div>
    </el-dialog>
  </div>
</template>

<script>
import userApi from '@/api/user'

export default {
  name: 'UserList',
  data() {
    // 验证确认密码
    const validateConfirmPassword = (rule, value, callback) => {
      if (value !== this.resetPwdForm.password) {
        callback(new Error('两次输入的密码不一致'))
      } else {
        callback()
      }
    }
    
    return {
      list: [], // 用户列表
      total: 0, // 总记录数
      listLoading: true, // 加载状态
      listQuery: { // 查询参数
        page: 1,
        pageSize: 10,
        username: '',
        phone: '',
        startDate: '',
        endDate: ''
      },
      dateRange: [], // 日期范围
      
      // 用户详情
      detailDialogVisible: false,
      detailLoading: false,
      currentUser: {
        addresses: [],
        recentOrders: []
      },
      
      // 订单状态选项
      orderStatusOptions: {
        'PENDING_PAYMENT': '待付款',
        'PAID': '已付款',
        'SHIPPED': '已发货',
        'COMPLETED': '已完成',
        'CANCELLED': '已取消',
        'REFUNDED': '已退款'
      },
      
      // 重置密码
      resetPwdDialogVisible: false,
      resetPwdSubmitting: false,
      resetPwdForm: {
        userId: '',
        password: '',
        confirmPassword: ''
      },
      resetPwdRules: {
        password: [
          { required: true, message: '请输入新密码', trigger: 'blur' },
          { min: 6, max: 20, message: '长度在 6 到 20 个字符', trigger: 'blur' }
        ],
        confirmPassword: [
          { required: true, message: '请确认新密码', trigger: 'blur' },
          { validator: validateConfirmPassword, trigger: 'blur' }
        ]
      }
    }
  },
  created() {
    this.fetchData()
  },
  methods: {
    // 获取用户名的首字母（用于头像显示）
    getInitials(username) {
      if (!username) return '用'
      return username.charAt(0).toUpperCase()
    },
    
    // 获取订单状态对应的标签类型
    getOrderStatusType(status) {
      const statusTypes = {
        'PENDING_PAYMENT': 'info',
        'PAID': 'warning',
        'SHIPPED': 'primary',
        'COMPLETED': 'success',
        'CANCELLED': 'danger',
        'REFUNDED': 'danger'
      }
      return statusTypes[status] || 'info'
    },
    
    // 获取用户列表
    fetchData() {
      this.listLoading = true
      
      userApi.getList(this.listQuery)
        .then(response => {
          if (response.code === 0) {
            this.list = response.data.list || []
            this.total = response.data.total || 0
          } else {
            this.$message.error(response.message || '获取用户列表失败')
          }
          this.listLoading = false
        })
        .catch(error => {
          console.error('获取用户列表出错:', error)
          this.listLoading = false
          
          // 模拟数据（实际开发中应该删除）
          this.mockUserList()
        })
    },
    
    // 模拟用户数据（实际开发中应该删除）
    mockUserList() {
      this.list = [
        {
          id: 1,
          username: '张三',
          nickname: '茶客001',
          avatar: 'https://cube.elemecdn.com/0/88/03b0d39583f48206768a7534e55bcpng.png',
          phone: '13800138001',
          gender: 'MALE',
          registerTime: '2024-01-15 10:00:00',
          loginTime: '2024-03-28 09:15:30',
          orderCount: 8,
          spendAmount: 1256.00,
          status: true
        },
        {
          id: 2,
          username: '李四',
          nickname: '爱喝茶的人',
          avatar: '',
          phone: '13800138002',
          gender: 'MALE',
          registerTime: '2024-01-20 14:30:00',
          loginTime: '2024-03-27 16:20:45',
          orderCount: 5,
          spendAmount: 876.50,
          status: true
        },
        {
          id: 3,
          username: '王五',
          nickname: '茶道爱好者',
          avatar: 'https://cube.elemecdn.com/3/7c/3ea6beec64369c2642b92c6726f1epng.png',
          phone: '13800138003',
          gender: 'MALE',
          registerTime: '2024-02-05 09:15:00',
          loginTime: '2024-03-25 11:05:22',
          orderCount: 3,
          spendAmount: 562.00,
          status: true
        },
        {
          id: 4,
          username: '赵六',
          nickname: '',
          avatar: '',
          phone: '13800138004',
          gender: 'FEMALE',
          registerTime: '2024-02-10 16:45:00',
          loginTime: '2024-03-22 14:30:18',
          orderCount: 1,
          spendAmount: 268.00,
          status: true
        },
        {
          id: 5,
          username: '小明',
          nickname: '爱茶之人',
          avatar: '',
          phone: '13800138005',
          gender: 'MALE',
          registerTime: '2024-02-15 11:20:00',
          loginTime: '2024-03-24 08:45:10',
          orderCount: 2,
          spendAmount: 356.00,
          status: false
        }
      ]
      
      this.total = this.list.length
    },
    
    // 日期范围变更
    handleDateChange(val) {
      if (val) {
        this.listQuery.startDate = val[0]
        this.listQuery.endDate = val[1]
      } else {
        this.listQuery.startDate = ''
        this.listQuery.endDate = ''
      }
    },
    
    // 搜索
    handleSearch() {
      this.listQuery.page = 1
      this.fetchData()
    },
    
    // 重置查询条件
    resetQuery() {
      this.dateRange = []
      this.listQuery = {
        page: 1,
        pageSize: 10,
        username: '',
        phone: '',
        startDate: '',
        endDate: ''
      }
      this.fetchData()
    },
    
    // 每页数量改变
    handleSizeChange(val) {
      this.listQuery.pageSize = val
      this.fetchData()
    },
    
    // 页码改变
    handleCurrentChange(val) {
      this.listQuery.page = val
      this.fetchData()
    },
    
    // 状态变更
    handleStatusChange(row) {
      const status = row.status
      const statusText = status ? '启用' : '禁用'
      
      userApi.updateStatus(row.id, { status })
        .then(response => {
          if (response.code === 0) {
            this.$message.success(`已${statusText}该用户`)
          } else {
            // 恢复原状态
            row.status = !status
            this.$message.error(response.message || `${statusText}用户失败`)
          }
        })
        .catch(error => {
          console.error('更新用户状态出错:', error)
          // 恢复原状态
          row.status = !status
          this.$message.error(`${statusText}用户失败，请重试`)
        })
    },
    
    // 查看用户详情
    handleViewDetail(row) {
      this.detailDialogVisible = true
      this.detailLoading = true
      
      userApi.getDetail(row.id)
        .then(response => {
          if (response.code === 0) {
            this.currentUser = response.data || {}
          } else {
            this.$message.error(response.message || '获取用户详情失败')
          }
          this.detailLoading = false
        })
        .catch(error => {
          console.error('获取用户详情出错:', error)
          this.detailLoading = false
          
          // 模拟数据（实际开发中应该删除）
          this.mockUserDetail(row)
        })
    },
    
    // 模拟用户详情数据（实际开发中应该删除）
    mockUserDetail(user) {
      // 基础信息复制
      this.currentUser = { ...user }
      
      // 附加 OpenId
      this.currentUser.openId = 'oE7Vl5_slKDSz1a3btEMnJ4Jx9Yo'
      
      // 最近消费时间
      this.currentUser.lastOrderTime = '2024-03-27 10:25:12'
      
      // 收货地址
      this.currentUser.addresses = [
        {
          id: 1,
          name: user.username,
          phone: user.phone,
          province: '浙江省',
          city: '杭州市',
          district: '西湖区',
          detail: '西溪路556号',
          isDefault: true
        },
        {
          id: 2,
          name: user.username,
          phone: user.phone,
          province: '浙江省',
          city: '杭州市',
          district: '滨江区',
          detail: '网商路599号',
          isDefault: false
        }
      ]
      
      // 最近订单
      this.currentUser.recentOrders = [
        {
          id: 1,
          orderNumber: 'T20240327001',
          createTime: '2024-03-27 10:25:12',
          totalAmount: 278.00,
          status: 'PAID'
        },
        {
          id: 2,
          orderNumber: 'T20240310002',
          createTime: '2024-03-10 14:30:45',
          totalAmount: 358.00,
          status: 'COMPLETED'
        },
        {
          id: 3,
          orderNumber: 'T20240225003',
          createTime: '2024-02-25 09:15:30',
          totalAmount: 198.00,
          status: 'COMPLETED'
        }
      ]
    },
    
    // 重置密码
    handleResetPassword(row) {
      this.resetPwdForm = {
        userId: row.id,
        password: '',
        confirmPassword: ''
      }
      this.resetPwdDialogVisible = true
      this.$nextTick(() => {
        this.$refs.resetPwdForm && this.$refs.resetPwdForm.clearValidate()
      })
    },
    
    // 确认重置密码
    confirmResetPassword() {
      this.$refs.resetPwdForm.validate(valid => {
        if (valid) {
          this.resetPwdSubmitting = true
          
          userApi.resetPassword(this.resetPwdForm.userId, { password: this.resetPwdForm.password })
            .then(response => {
              if (response.code === 0) {
                this.$message.success('密码重置成功')
                this.resetPwdDialogVisible = false
              } else {
                this.$message.error(response.message || '密码重置失败')
              }
              this.resetPwdSubmitting = false
            })
            .catch(error => {
              console.error('重置密码出错:', error)
              this.$message.error('密码重置失败，请重试')
              this.resetPwdSubmitting = false
            })
        }
      })
    }
  }
}
</script>

<style lang="scss" scoped>
.user-list-container {
  padding: 20px;
  
  .filter-container {
    margin-bottom: 20px;
  }
  
  .user-info {
    display: flex;
    align-items: center;
    
    .user-detail {
      margin-left: 10px;
      
      .username {
        font-size: 14px;
        font-weight: 500;
        color: #303133;
      }
      
      .nickname {
        font-size: 12px;
        color: #909399;
      }
    }
  }
  
  .pagination-container {
    margin-top: 20px;
    text-align: right;
  }
  
  .amount {
    font-weight: bold;
    color: #F56C6C;
  }
}

// 用户详情样式
.user-detail-container {
  .detail-section {
    margin-bottom: 30px;
    
    .section-title {
      font-size: 16px;
      font-weight: bold;
      color: #303133;
      margin-bottom: 15px;
      padding-bottom: 10px;
      border-bottom: 1px solid #EBEEF5;
    }
  }
  
  .user-profile {
    display: flex;
    margin-bottom: 20px;
    
    .user-avatar {
      margin-right: 20px;
    }
    
    .user-basic-info {
      flex: 1;
      
      .info-item {
        margin-bottom: 10px;
        
        .label {
          color: #909399;
          margin-right: 8px;
        }
        
        .value {
          color: #303133;
          font-weight: 500;
